#!/usr/bin/env node
/**
 * Photo Slideshow Builder — mechanical pipeline (no LLM calls)
 *
 * Two modes:
 *   --prepare: Groups photos from Drive into slideshow assignments, saves to queue.
 *              Agent then generates slideTexts + caption for each entry.
 *   (default): Reads queue entries with slideTexts + caption, applies overlays,
 *              creates Dropspace launches.
 *
 * Text content is ALWAYS generated by the agent (not inline LLM calls).
 * This script is purely mechanical: download, overlay, upload.
 *
 * Uses shared overlay module from core/overlay.js.
 * Tracks used photos in {event}-used-photos.json to prevent reuse.
 *
 * Usage:
 *   # Step 1: Prepare slideshow assignments (agent generates text after this)
 *   node create-slideshows.js --app myapp --event my-event --prepare
 *
 *   # Step 2: Build launches from queue entries that have text
 *   node create-slideshows.js --app myapp --event my-event
 *
 * Env: App's API key (from apiKeyEnv in app.json), GWS auth vars
 */

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');

// ── Args ──
const args = process.argv.slice(2);
function getArg(name, def) {
  const i = args.indexOf(`--${name}`);
  return i >= 0 && i + 1 < args.length ? args[i + 1] : def;
}
function hasFlag(name) { return args.includes(`--${name}`); }

const APP = getArg('app', null);
if (!APP) { console.error('Usage: node create-slideshows.js --app <name> --event <event> [--prepare] [--platform <platform>] [--photos-per-slide 3]'); process.exit(1); }

const paths = require('../../core/paths');
const appConfigPath = path.join(paths.appRoot(APP), 'app.json');
const appConfig = JSON.parse(fs.readFileSync(appConfigPath, 'utf-8'));
const PLATFORM = getArg('platform', Object.keys(appConfig.platforms || {})[0] || 'tiktok');
const PHOTOS_PER_SLIDE = parseInt(getArg('photos-per-slide', '3'));
const CONNECTION_ID = appConfig.platforms?.[PLATFORM]?.connectionId || appConfig.connections?.[PLATFORM];
if (!CONNECTION_ID) { console.error(`❌ No connectionId for ${PLATFORM} in ${APP}/app.json`); process.exit(1); }
const EVENT = getArg('event', null);
if (!EVENT) { console.error('❌ --event is required (e.g. --event my-event)'); process.exit(1); }
const PREPARE_MODE = hasFlag('prepare');

const DATA_DIR = paths.appRoot(APP);
const USED_FILE = path.join(DATA_DIR, 'config', EVENT, 'used-photos.json');
const STRATEGY_FILE = path.join(DATA_DIR, PLATFORM, 'strategy.json');
const CONTEXT_FILE = path.join(DATA_DIR, 'config', EVENT, 'CONTEXT.md');

// Read Drive folder ID from event CONTEXT.md
const contextContent = fs.readFileSync(CONTEXT_FILE, 'utf-8');
const folderMatch = contextContent.match(/\*\*Folder ID:\*\*\s*`([^`]+)`/);
if (!folderMatch) {
  console.error(`❌ No Drive Folder ID found in ${CONTEXT_FILE}`);
  process.exit(1);
}
const DRIVE_FOLDER_ID = folderMatch[1];

const API_KEY = process.env[appConfig.apiKeyEnv];
if (!API_KEY && !PREPARE_MODE) {
  console.error(`Missing ${appConfig.apiKeyEnv} for ${APP}`);
  process.exit(1);
}

// ── Overlay module (only needed in build mode) ──
let initCanvas, addOverlay;
if (!PREPARE_MODE) {
  ({ initCanvas, addOverlay } = require(path.join(__dirname, '..', '..', 'core', 'overlay')));
}

// ── Drive helpers ──
let _driveAccessToken = null;

async function getDriveToken() {
  if (_driveAccessToken) return _driveAccessToken;
  const opToken = execSync(
    `grep OP_SERVICE_ACCOUNT_TOKEN ~/.bashrc | head -1 | cut -d'"' -f2`,
    { encoding: 'utf-8' }
  ).trim();
  let credsJson;
  if (process.env.GOOGLE_WORKSPACE_CLI_CREDENTIALS_FILE) {
    credsJson = fs.readFileSync(process.env.GOOGLE_WORKSPACE_CLI_CREDENTIALS_FILE, 'utf-8');
  } else if (process.env.GWS_VAULT_PATH) {
    credsJson = execSync(
      `OP_SERVICE_ACCOUNT_TOKEN="${opToken}" op read 'op://${process.env.GWS_VAULT_PATH}'`,
      { encoding: 'utf-8' }
    ).trim();
  } else {
    throw new Error('Set GOOGLE_WORKSPACE_CLI_CREDENTIALS_FILE or GWS_VAULT_PATH');
  }
  const creds = JSON.parse(credsJson);
  const resp = await fetch('https://oauth2.googleapis.com/token', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `client_id=${creds.client_id}&client_secret=${creds.client_secret}&refresh_token=${creds.refresh_token}&grant_type=refresh_token`,
  });
  if (!resp.ok) throw new Error(`Google OAuth error: ${resp.status}`);
  const data = await resp.json();
  _driveAccessToken = data.access_token;
  return _driveAccessToken;
}

async function driveAPI(endpoint) {
  const token = await getDriveToken();
  const resp = await fetch(`https://www.googleapis.com/drive/v3/${endpoint}`, {
    headers: { 'Authorization': `Bearer ${token}` },
  });
  if (!resp.ok) throw new Error(`Drive API ${resp.status}: ${await resp.text()}`);
  return resp.json();
}

async function listDriveSubfolders(parentId) {
  const q = encodeURIComponent(`'${parentId}' in parents and mimeType='application/vnd.google-apps.folder'`);
  const data = await driveAPI(`files?q=${q}&fields=files(id,name)&pageSize=50`);
  return data.files || [];
}

async function listDriveImages(folderId) {
  const q = encodeURIComponent(`'${folderId}' in parents and mimeType contains 'image/'`);
  const data = await driveAPI(`files?q=${q}&fields=files(id,name,mimeType)&pageSize=100`);
  return data.files || [];
}

async function downloadDriveFile(fileId, outPath) {
  const token = await getDriveToken();
  const resp = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
    headers: { 'Authorization': `Bearer ${token}` },
  });
  if (!resp.ok) throw new Error(`Drive download ${resp.status}`);
  const buffer = Buffer.from(await resp.arrayBuffer());
  fs.writeFileSync(outPath, buffer);
  const resized = outPath.replace(/\.(jpg|jpeg|png)$/i, '-resized.jpg');
  try {
    execSync(
      `~/bin/ffmpeg -y -i "${outPath}" -vf "scale=1080:1920:force_original_aspect_ratio=increase,crop=1080:1920" -q:v 3 "${resized}" 2>/dev/null`,
      { encoding: 'utf-8' }
    );
    fs.renameSync(resized, outPath);
  } catch {}
}

// ── Photo tracking ──
function loadUsed() {
  try { return JSON.parse(fs.readFileSync(USED_FILE, 'utf-8')); }
  catch { return { usedIds: [], slideshowCount: 0 }; }
}
function saveUsed(data) {
  fs.writeFileSync(USED_FILE, JSON.stringify(data, null, 2));
}

// ── Dropspace API ──
async function createLaunch(title, caption, photoFiles) {
  const compressedFiles = [];
  for (const f of photoFiles) {
    if (f.endsWith('.png')) {
      const jpgPath = f.replace('.png', '.jpg');
      execSync(`~/bin/ffmpeg -y -i "${f}" -q:v 4 "${jpgPath}" 2>/dev/null`);
      compressedFiles.push(jpgPath);
    } else {
      compressedFiles.push(f);
    }
  }

  const media = compressedFiles.map(f => ({
    source: 'base64',
    data: fs.readFileSync(f).toString('base64'),
    filename: path.basename(f),
    mime_type: 'image/jpeg',
  }));

  for (const f of compressedFiles) {
    if (f !== photoFiles[compressedFiles.indexOf(f)]) {
      try { fs.unlinkSync(f); } catch {}
    }
  }

  const platformContent = {};
  if (PLATFORM === 'tiktok') {
    platformContent.tiktok = {
      content: caption || title,
      tiktok_settings: {
        privacy_level: appConfig.platforms?.[PLATFORM]?.tiktokPrivacyLevel || 'SELF_ONLY',
        auto_add_music: appConfig.platforms?.[PLATFORM]?.tiktokSettings?.auto_add_music ?? false,
        allow_comments: appConfig.platforms?.[PLATFORM]?.tiktokSettings?.allow_comments ?? true,
        allow_duet: appConfig.platforms?.[PLATFORM]?.tiktokSettings?.allow_duet ?? true,
        allow_stitch: appConfig.platforms?.[PLATFORM]?.tiktokSettings?.allow_stitch ?? true,
        is_commercial: appConfig.platforms?.[PLATFORM]?.tiktokSettings?.is_commercial ?? false,
        is_your_brand: appConfig.platforms?.[PLATFORM]?.tiktokSettings?.is_your_brand ?? false,
        is_branded_content: appConfig.platforms?.[PLATFORM]?.tiktokSettings?.is_branded_content ?? false,
      },
    };
  } else {
    platformContent[PLATFORM] = { content: caption || title };
  }

  const body = {
    title,
    product_description: `${appConfig.name} - ${appConfig.description}`,
    platforms: [PLATFORM],
    user_platform_accounts: { [PLATFORM]: CONNECTION_ID },
    media,
    platform_contents: platformContent,
  };

  const resp = await fetch('https://api.dropspace.dev/launches', {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(body),
  });

  if (!resp.ok) {
    const text = await resp.text();
    throw new Error(`Dropspace API ${resp.status}: ${text}`);
  }
  return resp.json();
}

// ── Shared: group photos into slideshows ──
async function groupPhotosIntoSlideshows() {
  // 1. Get all photos from Drive
  const subfolders = await listDriveSubfolders(DRIVE_FOLDER_ID);
  console.log(`Found ${subfolders.length} folders: ${subfolders.map(f => f.name).join(', ')}`);

  const allPhotos = [];
  for (const folder of subfolders) {
    const images = await listDriveImages(folder.id);
    for (const img of images) {
      allPhotos.push({ id: img.id, name: img.name, folder: folder.name });
    }
  }
  console.log(`Total photos: ${allPhotos.length}`);

  // 2. Load face metadata
  const METADATA_FILE = path.join(DATA_DIR, 'config', EVENT, 'photo-metadata.json');
  let faceSet = new Set();
  try {
    const meta = JSON.parse(fs.readFileSync(METADATA_FILE, 'utf-8'));
    faceSet = new Set(meta.photos.filter(p => p.hasFace).map(p => p.id));
    console.log(`Face metadata: ${faceSet.size} photos with faces`);
  } catch {
    console.warn('⚠️ No photo-metadata.json — face-first selection disabled');
  }

  // 3. Filter out used photos
  const used = loadUsed();
  const usedSet = new Set(used.usedIds);
  const available = allPhotos.filter(p => !usedSet.has(p.id));
  console.log(`Available (unused): ${available.length}`);

  if (available.length < PHOTOS_PER_SLIDE) {
    console.log('Not enough unused photos for even 1 slideshow. Done.');
    return { slideshows: [], faceSet, used };
  }

  // 4. Split into face/non-face, shuffle
  const facePhotos = available.filter(p => faceSet.has(p.id));
  const noFacePhotos = available.filter(p => !faceSet.has(p.id));
  console.log(`With faces: ${facePhotos.length}, Without: ${noFacePhotos.length}`);

  function shuffle(arr) {
    for (let i = arr.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [arr[i], arr[j]] = [arr[j], arr[i]];
    }
    return arr;
  }
  shuffle(facePhotos);
  shuffle(noFacePhotos);

  // 5. Build slideshows: slide 1 = face photo, rest = mix
  const slideshows = [];
  const remainingPool = [...noFacePhotos];
  const faceQueue = [...facePhotos];

  while (faceQueue.length >= 1 && (faceQueue.length + remainingPool.length) >= PHOTOS_PER_SLIDE) {
    const slide1 = faceQueue.shift();
    const others = [];
    for (let need = PHOTOS_PER_SLIDE - 1; need > 0; need--) {
      if (remainingPool.length > 0) {
        others.push(remainingPool.shift());
      } else if (faceQueue.length > 0) {
        others.push(faceQueue.shift());
      } else {
        break;
      }
    }
    if (others.length === PHOTOS_PER_SLIDE - 1) {
      slideshows.push([slide1, ...others]);
    } else {
      const leftovers = [slide1, ...others];
      if (slideshows.length > 0 && leftovers.length > 0) {
        slideshows[slideshows.length - 1].push(...leftovers);
      }
      break;
    }
  }

  // Distribute leftover photos round-robin across last few slideshows
  const stragglers = [...faceQueue, ...remainingPool];
  if (stragglers.length > 0 && slideshows.length > 0) {
    let idx = slideshows.length - 1;
    for (const straggler of stragglers) {
      slideshows[idx].push(straggler);
      idx--;
      if (idx < 0) idx = slideshows.length - 1;
    }
  }

  console.log(`Grouped into ${slideshows.length} slideshows`);
  return { slideshows, faceSet, used };
}

// ══════════════════════════════════════════════════════════════
// MODE 1: --prepare — group photos, save to queue for agent to add text
// ══════════════════════════════════════════════════════════════
async function prepareMode() {
  console.log('📸 Prepare mode: grouping photos into slideshow assignments\n');

  const { slideshows, used } = await groupPhotosIntoSlideshows();
  if (slideshows.length === 0) return;

  const strategy = JSON.parse(fs.readFileSync(STRATEGY_FILE, 'utf-8'));
  strategy.postQueue = strategy.postQueue || [];

  const newEntries = [];
  for (let i = 0; i < slideshows.length; i++) {
    const photos = slideshows[i];
    const slideNum = used.slideshowCount + i + 1;
    const entry = {
      text: `slideshow ${slideNum}`,
      format: 'photo-slideshow',
      status: 'needs-text', // agent must fill slideTexts + caption before build
      slideTexts: null,     // agent fills: ["hook", "context", "cta"]
      caption: null,        // agent fills: TikTok caption string
      photos: photos.map(p => ({ id: p.id, name: p.name, folder: p.folder })),
      source: 'drive-photos',
      addedAt: new Date().toISOString(),
    };
    newEntries.push(entry);

    // Track used photos
    for (const p of photos) {
      used.usedIds.push(p.id);
    }
  }

  used.slideshowCount += newEntries.length;
  saveUsed(used);

  strategy.postQueue.push(...newEntries);
  fs.writeFileSync(STRATEGY_FILE, JSON.stringify(strategy, null, 2));

  console.log(`\n✅ Added ${newEntries.length} slideshow assignments to queue (status: needs-text)`);
  console.log(`   Agent must generate slideTexts + caption for each entry before running build mode.`);
  console.log(`\n📋 Queue entries needing text:`);
  for (const e of newEntries) {
    console.log(`   - ${e.text}: ${e.photos.length} photos (${e.photos.map(p => p.folder).join(', ')})`);
  }
}

// ══════════════════════════════════════════════════════════════
// MODE 2: (default) — build launches from queue entries that have text
// ══════════════════════════════════════════════════════════════
async function buildMode() {
  console.log('📸 Build mode: creating launches from queue entries with text\n');

  try {
    initCanvas();
    console.log('✅ Canvas module loaded for text overlays\n');
  } catch (err) {
    console.error(`❌ ${err.message}`);
    process.exit(1);
  }

  // Load face metadata for overlay positioning
  const METADATA_FILE = path.join(DATA_DIR, 'config', EVENT, 'photo-metadata.json');
  let faceSet = new Set();
  try {
    const meta = JSON.parse(fs.readFileSync(METADATA_FILE, 'utf-8'));
    faceSet = new Set(meta.photos.filter(p => p.hasFace).map(p => p.id));
  } catch {}

  const strategy = JSON.parse(fs.readFileSync(STRATEGY_FILE, 'utf-8'));
  const ready = (strategy.postQueue || []).filter(e =>
    e.format === 'photo-slideshow' && e.slideTexts && e.caption && !e.launchId
  );

  if (ready.length === 0) {
    console.log('No queue entries ready to build (need slideTexts + caption, no launchId yet).');
    console.log('Run with --prepare first, then have the agent generate text.');
    return;
  }

  console.log(`Found ${ready.length} entries ready to build\n`);

  for (const entry of ready) {
    const photos = entry.photos;
    const slideTexts = entry.slideTexts;
    const caption = entry.caption;

    if (slideTexts.length !== photos.length) {
      console.warn(`⚠️ ${entry.text}: slideTexts count (${slideTexts.length}) ≠ photos count (${photos.length}), skipping`);
      continue;
    }

    try {
      console.log(`  📷 ${entry.text}: ${photos.map(p => `${p.name}(${p.folder})`).join(', ')}`);

      // Download photos from Drive
      const photoFiles = [];
      for (const p of photos) {
        const outFile = path.join('/tmp', `sj-${p.id}.jpg`);
        console.log(`     ⬇️  Downloading ${p.name}...`);
        await downloadDriveFile(p.id, outFile);
        photoFiles.push(outFile);
      }

      // Apply text overlays (face-aware positioning)
      const overlayedFiles = [];
      for (let j = 0; j < photoFiles.length; j++) {
        const overlayedPath = photoFiles[j].replace(/\.(jpg|jpeg|png)$/i, '-overlay.png');
        const photoHasFace = faceSet.has(photos[j].id);
        await addOverlay(photoFiles[j], slideTexts[j], overlayedPath, {
          preset: 'photo-slideshow',
          slideIndex: j,
          hasFace: photoHasFace,
        });
        overlayedFiles.push(overlayedPath);
        console.log(`     🎨 Overlay applied to slide ${j + 1}${photoHasFace ? ' (face → bottom-safe)' : ''}`);
      }

      // Create Dropspace launch
      const launch = await createLaunch(entry.text, caption, overlayedFiles);

      // Cleanup temp files
      for (const f of [...photoFiles, ...overlayedFiles]) {
        try { fs.unlinkSync(f); } catch {}
      }

      const launchId = launch.data?.id || launch.id;
      entry.launchId = launchId;
      entry.status = 'built';
      console.log(`     ✅ Launch created: ${launchId}`);

      await new Promise(r => setTimeout(r, 1000));
    } catch (err) {
      console.error(`     ❌ Failed: ${err.message}`);
      entry.status = 'build-failed';
    }
  }

  // Save updated queue
  fs.writeFileSync(STRATEGY_FILE, JSON.stringify(strategy, null, 2));
  const built = ready.filter(e => e.status === 'built').length;
  console.log(`\n✅ Built ${built}/${ready.length} launches`);
}

// ── Main ──
async function main() {
  if (PREPARE_MODE) {
    await prepareMode();
  } else {
    await buildMode();
  }
}

main().catch(err => {
  console.error(`Fatal: ${err.message}`);
  process.exit(1);
});
